def compute_mrr(scores):
    if not scores:
        return 0.0
    return sum(
        1.0 / r for r in scores
    ) / len(scores)

class BaseEvaluator:
    def evaluate(self, data):
        raise NotImplementedError
    def batch_evaluate(self, items):
        results = []
        for item in items:
            results.append(self.evaluate(item))
        return results
    def name(self):
        return type(self).__name__

class MetricsCollector:
    def run(self, inputs):
        for inp in inputs:
            score = self._score(inp)
            self.scores.append(
                score
            )

class MetricsCollector:
    def report(self):
        return {
            'mean': sum(self.scores) / max(len(self.scores), 1),
            'count': len(self.scores),
            'tags': self.tags,
        }
